update public.lessons l set enhancements = $ench${"industryStory":"Two candidates applied for the same junior QA role. One said \"I understand testing\". The other shared a public portfolio: test cases, a bug report, a Postman collection and an RTM. The second got the interview — because they proved it instead of claiming it.","visualAid":{"type":"comparison","title":"Claims vs evidence","headers":["","Just a claim","A portfolio"],"rows":[["\"I can write test cases\"","Unverified","Here is a structured pack"],["\"I understand defects\"","Unverified","Here is a professional bug report"],["\"I can test APIs\"","Unverified","Here is a Postman collection"]]},"davidTip":"For someone without years of experience, a portfolio is the single most persuasive thing you can show. As a hiring manager, I would rather see one real artefact than read three paragraphs of \"I am passionate about quality\".","miniChallenge":"List the artefacts you have already created across this course that could go into your portfolio.","modelAnswer":"## Example\nTest case pack (Module 2), professional bug report (Module 3), agile acceptance-criteria example (Module 4), RTM (Module 5), Postman collection (Module 6), SQL validation snippets (Module 7), AI-assisted testing example (Module 9).","portfolioBuilder":"This module assembles everything you have built into one coherent portfolio — the centrepiece you will point employers to."}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = '90-day-software-testing-career-roadmap'
  and m.module_number = 10 and l.lesson_number = 1;

update public.lessons l set enhancements = $ench${"industryStory":"A candidate's portfolio had twenty files with no explanation — the reviewer could not tell what was good. A curated set of six artefacts, each with a line of context, would have made far more impact. Quality and clarity beat quantity.","visualAid":{"type":"comparison","title":"A strong QA portfolio includes","headers":["Artefact","What it proves"],"rows":[["Test plan / strategy snapshot","You plan, not just execute"],["Test case pack","You design coverage with techniques"],["Professional bug report","You communicate defects clearly"],["RTM","You think about traceability"],["API collection (Postman)","You test beyond the UI"],["Exploratory charter + notes","You test creatively"]]},"davidTip":"Six strong, well-explained pieces beat twenty unexplained ones. Curate ruthlessly, and add a two-line note to each artefact saying what it demonstrates — reviewers should never have to guess.","miniChallenge":"Choose the six artefacts you will include and write a one-line \"what this demonstrates\" note for each.","modelAnswer":"## Example\n\"Bug report — shows I can document a critical defect so a developer can fix it fast.\" \"RTM — shows I map requirements to tests and can prove coverage.\"","resourcePreview":{"name":"Final Portfolio Project Workbook","purpose":"Guides you to assemble a complete, professional QA portfolio.","whenToUse":"Use it as the checklist while building your portfolio.","formats":["DOCX","PDF"]}}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = '90-day-software-testing-career-roadmap'
  and m.module_number = 10 and l.lesson_number = 2;

update public.lessons l set enhancements = $ench${"industryStory":"A reviewer opened a portfolio repo and gave up — no README, files named \"doc1, doc2\", nothing explained. Another opened with a clear intro and structure and spent ten minutes exploring. Structure decides whether your work gets seen.","badGood":{"label":"portfolio structure","bad":"A folder of files: doc1.pdf, test.xlsx, notes.txt — no intro, no order.","good":"A README intro (\"QA portfolio — what I can do\"), folders by skill (test-design, defects, api, sql), each artefact with a short context note."},"davidTip":"Treat your portfolio like a product with a front door. A clear README and a logical structure tell a reviewer where to look and what they are seeing — that first impression is doing a lot of the work.","miniChallenge":"Sketch the structure of your portfolio: the intro, the sections, and where each artefact lives.","modelAnswer":"## Example\nREADME (who I am + what this shows) → /test-design (test case pack) → /defects (bug report) → /api (Postman collection) → /data (SQL + RTM) → /ai (AI-assisted example). Each folder has a one-line readme.","portfolioBuilder":"A clean structure and README is itself portfolio evidence — it shows organisation and communication, qualities every QA team values."}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = '90-day-software-testing-career-roadmap'
  and m.module_number = 10 and l.lesson_number = 3;

update public.lessons l set enhancements = $ench${"industryStory":"In an interview, a candidate opened their portfolio and walked through a bug report in 60 seconds: what it was, the risk, what they did, what it proved. The interviewer was sold — not by the artefact alone, but by how clearly they presented it.","badGood":{"label":"showcasing an artefact","bad":"\"Here's a bug report I did.\" (then silence)","good":"\"This is a checkout bug I found. It blocked payments (why it mattered). I reproduced it, isolated it to a recent change, and documented it with evidence (what I did). It shows I can communicate a critical issue clearly (what it proves).\""},"davidTip":"Prepare a 60-second walkthrough for each artefact: what it is, why it mattered, what you did, what it demonstrates. Being able to talk through your work confidently is often what tips a close interview decision.","miniChallenge":"Write a 60-second walkthrough for one of your artefacts using the what / why / how / proves structure.","modelAnswer":"## Example — RTM\n\"This is a requirements traceability matrix for a small feature (what). It maps each requirement to the tests that cover it (why — proves coverage). I built it from my test cases and linked the one defect I found (how). It shows I think about coverage and traceability, not just individual tests (proves).\"","managersReview":{"intro":"If you walked me through your portfolio as a hiring manager, I would look for:","strengths":["Clear what/why/how/proves for each piece","Confidence and concision","Tying each artefact to a real skill"],"gaps":["Showing files with no narrative","Rambling without structure","No link to the role’s needs"],"improvements":["Rehearse a 60-second walkthrough per artefact","Lead with impact, not mechanics","Connect each piece to the job"]}}$ench$::jsonb
from public.modules m join public.courses c on c.id = m.course_id
where l.module_id = m.id and c.slug = '90-day-software-testing-career-roadmap'
  and m.module_number = 10 and l.lesson_number = 4;

update public.lessons l set enhancements = $ench${"davidTip":"For this assignment, publish the portfolio properly (public repo or site) with working links and a clear README. A reviewer who hits a broken or private link simply moves on — make it effortless to explore.","miniChallenge":"Before submitting, open your portfolio as if you were a stranger: can you tell what it is, navigate it, and open every artefact within a minute?","managersReview":{"intro":"If I received your portfolio as a hiring manager, I would look for:","strengths":["Clear intro and logical structure","Curated, well-explained artefacts","Everything public and working"],"gaps":["No context on artefacts","Quantity over quality","Broken or private links"],"improvements":["Add a what-it-demonstrates note per artefact","Curate to your strongest pieces","Verify every link is public and working"]},"portfolioBuilder":"This is the milestone: your portfolio is now a real, presentable asset. Keep refining it — it will do more for your job search than any single line on your CV."}$ench$::jsonb
